@using System.Threading
@implements IDisposable
@inject IProductService ProductService

<div class="product-search">
    <input type="text"
           placeholder="Search products…"
           @bind="searchText"
           @bind:event="oninput"
           @bind:after="OnSearchTextChanged" />

    @if (isLoading)
    {
        <div class="product-search-status">Searching…</div>
    }
    else if (errorMessage is not null)
    {
        <div class="product-search-error">
            <span>@errorMessage</span>
            <button @onclick="Retry">Retry</button>
        </div>
    }
    else if (hasSearched && products.Count == 0)
    {
        <div class="product-search-status">No products found.</div>
    }

    @if (products.Count > 0)
    {
        <div class="product-search-results">
            @foreach (var product in products)
            {
                <div class="product-card" @onclick="() => SelectProduct(product)">
                    <img src="@product.ImageUrl" alt="@product.Name" loading="lazy" />
                    <div class="product-card-body">
                        <h4>@product.Name</h4>
                        <span class="product-card-price">@product.Price.ToString("C")</span>
                    </div>
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private string searchText = string.Empty;
    private List<Product> products = new();
    private bool isLoading;
    private bool hasSearched;
    private string? errorMessage;

    private Timer? debounceTimer;
    private CancellationTokenSource? searchCts;

    private async Task OnSearchTextChanged()
    {
        debounceTimer?.Dispose();

        var query = searchText.Trim();
        if (string.IsNullOrEmpty(query))
        {
            CancelInflightSearch();
            products = new();
            hasSearched = false;
            errorMessage = null;
            isLoading = false;
            return;
        }

        debounceTimer = new Timer(_ => InvokeAsync(() => ExecuteSearch(query)), null, 300, Timeout.Infinite);
    }

    private async Task ExecuteSearch(string query)
    {
        CancelInflightSearch();

        var cts = new CancellationTokenSource();
        searchCts = cts;

        isLoading = true;
        errorMessage = null;
        StateHasChanged();

        try
        {
            var results = await ProductService.SearchAsync(query, cts.Token);

            if (cts.Token.IsCancellationRequested)
                return;

            products = results;
            hasSearched = true;
            errorMessage = null;
        }
        catch (OperationCanceledException)
        {
            // Search was superseded — discard silently.
            return;
        }
        catch (Exception)
        {
            if (cts.Token.IsCancellationRequested)
                return;

            products = new();
            errorMessage = "Something went wrong. Please try again.";
        }
        finally
        {
            if (!cts.Token.IsCancellationRequested)
            {
                isLoading = false;
                StateHasChanged();
            }
        }
    }

    private async Task Retry() => await ExecuteSearch(searchText.Trim());

    private async Task SelectProduct(Product product) => await OnProductSelected.InvokeAsync(product);

    private void CancelInflightSearch()
    {
        searchCts?.Cancel();
        searchCts?.Dispose();
        searchCts = null;
    }

    public void Dispose()
    {
        debounceTimer?.Dispose();
        CancelInflightSearch();
    }
}

